candidate.raw_text:
[
    {
        "step": 1,
        "concept": "Review Precision and Recall",
        "description": "Deepen understanding of precision and recall metrics, focusing on their trade-offs. Consider a model that has high precision but low recall—why might this be problematic in defect detection? This challenges the assumption that high precision alone is sufficient.",
        "resources": [
            "https://developers.google.com/machine-learning/crash-course/classification/precision-and-recall",
            "https://machinelearningmastery.com/precision-recall-and-f-measure-for-imbalanced-classification/"
        ]
    },
    {
        "step": 2,
        "concept": "Understanding Thresholds in Binary Classification",
        "description": "Learn how classification thresholds affect the balance between false positives and false negatives. Explore how changing the threshold shifts the confusion matrix outcomes. Consider a scenario where lowering the threshold increases false positives but catches more defects—when is this trade-off acceptable?",
        "resources": [
            "https://towardsdatascience.com/understanding-classification-thresholds-5f3f3f3f3f3f",
            "https://scikit-learn.org/stable/auto_examples/model_selection/plot_precision_recall_threshold.html"
        ]
    },
    {
        "step": 3,
        "concept": "ROC Curve and AUC",
        "description": "Study the Receiver Operating Characteristic (ROC) curve and Area Under the Curve (AUC) as tools to evaluate classifier performance across thresholds. Challenge the idea that a higher AUC always means better threshold choice by considering cases where operational costs differ.",
        "resources": [
            "https://developers.google.com/machine-learning/crash-course/classification/roc-and-auc",
            "https://en.wikipedia.org/wiki/Receiver_operating_characteristic"
        ]
    },
    {
        "step": 4,
        "concept": "Precision-Recall Curve and F1 Score",
        "description": "Explore the precision-recall curve and how it helps in selecting thresholds, especially for imbalanced datasets like defect detection. Understand the F1 score as a harmonic mean of precision and recall. Consider a model with a high F1 score but poor real-world performance due to cost asymmetry of errors.",
        "resources": [
            "https://scikit-learn.org/stable/auto_examples/model_selection/plot_precision_recall.html",
            "https://machinelearningmastery.com/classification-accuracy-is-not-enough-more-performance-measures-you-can-use/"
        ]
    },
    {
        "step": 5,
        "concept": "Cost-Sensitive Threshold Tuning",
        "description": "Learn how to incorporate the cost of false positives and false negatives into threshold selection. Practice with examples where false negatives (missed defects) are more costly than false positives (false alerts). Test understanding by evaluating a threshold that minimizes overall cost but increases false positives significantly.",
        "resources": [
            "https://www.kdnuggets.com/2020/06/cost-sensitive-learning-machine-learning.html",
            "https://www.datascience.com/blog/cost-sensitive-classification"
        ]
    },
    {
        "step": 6,
        "concept": "Calibration of Classifier Probabilities",
        "description": "Understand the importance of probability calibration for reliable threshold tuning. Explore methods like Platt scaling and isotonic regression. Consider a classifier with well-separated classes but poorly calibrated probabilities—how does this affect threshold decisions?",
        "resources": [
            "https://scikit-learn.org/stable/modules/calibration.html",
            "https://machinelearningmastery.com/calibrated-classifier-for-probability-estimates-in-python/"
        ]
    },
    {
        "step": 7,
        "concept": "Practical Threshold Selection and Deployment",
        "description": "Apply knowledge to select thresholds based on business goals and risk tolerance. Learn to use validation data and cross-validation to test thresholds. Consider a deployment scenario where a threshold chosen on historical data leads to unexpected false positive rates in production—what could cause this discrepancy?",
        "resources": [
            "https://mlflow.org/docs/latest/tutorials-and-examples/tutorial.html#threshold-tuning",
            "https://www.oreilly.com/library/view/evaluating-machine-learning/9781492048750/ch04.html"
        ]
    }
]

