[
    {
        "step": 1,
        "concept": "Review Precision and Recall",
        "description": "Deepen understanding of precision and recall metrics, focusing on their trade-offs. Consider a model that has high precision but low recall and another with the opposite. Reflect on which might be preferable in defect detection scenarios and why.",
        "resources": [
            "https://developers.google.com/machine-learning/crash-course/classification/precision-and-recall",
            "https://machinelearningmastery.com/precision-recall-and-f-measure-for-imbalanced-classification/"
        ]
    },
    {
        "step": 2,
        "concept": "Understanding Thresholds in Binary Classification",
        "description": "Learn how classification thresholds affect the balance between false positives and false negatives. Explore how changing the threshold shifts the confusion matrix outcomes. Test your understanding by imagining a threshold that results in zero false positives but many false negatives—what does this imply for defect detection?",
        "resources": [
            "https://towardsdatascience.com/understanding-thresholds-in-binary-classification-9f3f3f1a7f3a",
            "https://scikit-learn.org/stable/auto_examples/model_selection/plot_precision_recall_threshold.html"
        ]
    },
    {
        "step": 3,
        "concept": "ROC Curve and AUC",
        "description": "Study the ROC curve and Area Under the Curve (AUC) as tools to evaluate classifier performance across thresholds. Consider a model with a high AUC but poor performance at a specific threshold—why might this happen, and how does it affect deployment decisions?",
        "resources": [
            "https://developers.google.com/machine-learning/crash-course/classification/roc-and-auc",
            "https://en.wikipedia.org/wiki/Receiver_operating_characteristic"
        ]
    },
    {
        "step": 4,
        "concept": "Precision-Recall Curve and F1 Score",
        "description": "Explore the precision-recall curve and the F1 score as metrics that combine precision and recall. Challenge yourself by comparing two models: one with a higher F1 score but lower precision, and another with the opposite. Which would you choose for defect detection alerts and why?",
        "resources": [
            "https://scikit-learn.org/stable/auto_examples/model_selection/plot_precision_recall.html",
            "https://machinelearningmastery.com/f1-score-for-imbalanced-classification/"
        ]
    },
    {
        "step": 5,
        "concept": "Cost-Sensitive Threshold Tuning",
        "description": "Learn how to incorporate the costs of false positives and false negatives into threshold selection. Imagine a scenario where false positives cause alert fatigue but false negatives miss critical defects. How would you adjust the threshold accordingly? Test this by designing thresholds for different cost scenarios.",
        "resources": [
            "https://www.kdnuggets.com/2020/06/cost-sensitive-learning-machine-learning.html",
            "https://towardsdatascience.com/threshold-tuning-for-classification-models-using-cost-matrix-4a0a3f3a1f3b"
        ]
    },
    {
        "step": 6,
        "concept": "Practical Threshold Selection and Deployment",
        "description": "Apply all previous concepts to real-world defect detection classifier outputs. Practice selecting thresholds based on business requirements and risk tolerance. Consider counter-examples where a threshold optimized on training data fails in production due to data drift or changing defect patterns.",
        "resources": [
            "https://mlflow.org/docs/latest/tutorials-and-examples.html#threshold-tuning",
            "https://www.datacamp.com/tutorial/threshold-moving"
        ]
    }
]

